SELECT SUM(number_of_members) AS total_members
FROM plan_participants
WHERE plan_id = 1;

SELECT SUM(funding_amount) AS total_funding
FROM plan_funding
WHERE plan_id = 1;

SELECT plan_name
FROM plans
ORDER BY plan_id;

SELECT age_group
FROM plan_demographics
WHERE plan_id = 1;

SELECT comment
FROM plan_comments
WHERE plan_id = 1;

SELECT participant_type, age
FROM plan_participants
WHERE participant_type = 'active';

SELECT performance_metric, AVG(performance_value) AS avg_performance
FROM plan_performance
GROUP BY performance_metric;

SELECT plan_name, volunteer AS total_volunteers
FROM plans
WHERE volunteer > 5;

SELECT AVG(average_tenure) AS avg_tenure
FROM plan_demographics
WHERE plan_id = 1;
